input.command:
ssh amd 'for r in rocm7.0 rocm6.4; do
  echo "=== $r : torch cp312 wheels ===";
  curl -s "https://download.pytorch.org/whl/$r/torch/" | grep -oE "torch-[0-9][^\"]*cp312[^\"]*linux_x86_64.whl" | sort -u | tail -5;
done' 2>&1

$u = $env:USERNAME
Write-Output "user: $u"
foreach ($f in @("$env:USERPROFILE\.ssh\config","$env:USERPROFILE\.ssh\id_ed25519")) {
  if (Test-Path $f) {
    cmd /c "icacls `"$f`" /inheritance:r" | Out-Null
    cmd /c "icacls `"$f`" /grant:r `"${u}:F`"" | Out-Null
    Write-Output "--- fixed: $f ---"
    cmd /c "icacls `"$f`""
  } else { Write-Output "MISSING: $f" }
}

ssh -o ConnectTimeout=20 amd 'for r in rocm7.0 rocm6.4 rocm6.3; do
  echo "=== $r ===";
  body=$(curl -sL "https://download.pytorch.org/whl/$r/torch/");
  echo "bytes=${#body}";
  echo "python tags: $(echo "$body" | grep -oE "cp3[0-9]+" | sort -u | tr "\n" " ")";
  echo "sample: $(echo "$body" | grep -oE "torch-[0-9][^\"<> ]*\.whl" | head -1)";
done' 2>&1
